INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '255.240。则该主机的主机号是(13)；可以直接接收该主机 广播 信息的地址 范围 是 (14)。', '["A. 0.0.0.8", "B. 0.0.0.120", "C. 0.0.0.15", "D. 0.0.0.240"]', '', '', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '255.240。则该主机的主机号是(13)；可以直接接收该主机广播信息的地址范围是 (14)。 参考答案：B 解析 ： 本题考查IP地址的基本知识。 IP地址由网络地址和主机地址两部分构成，主机地址可进一步划分为子网号和主机号两 部分，三者的区分需借助子网掩码实现。. 主机号是IP地址中去掉网络地址、子网号后的部分，其计算方法可简单利用公式“主机 号=IP地址AND(NOT(子网掩码))” 计算。 一台计算机发出的广播消息，只有处在同一子网(网络)内的计算机才能接收到。', '["A. 192.55.12.120?192.55.12.127", "B. 192.55.12.112?192.55.12.127", "C. 192.55.12.1?192.55.12.254", "D. 192.55.12.0?192.55.12.255"]', '', '', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '255.240)=192.55.12.112，IP地址的最后4位为主机号，范围为0?15，加在子 网号后面即可。', '["A.  ICMP，回送请求报文", "B.  UDP，17类型报文", "C.  TCP，SYN报文", "D. PING，测试报文"]', '', '', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'H.X.Y/16的模式分配，其中H为分支机构的序号(0表示公司总部，分支机构总数不会超过 200)。 对该工程师确定的逻辑设计内容的评价，恰当的是(27) 。 每个分支机构能连网的计算机的数量最多为(28)，配置 IP地址 时掩码是(29)。 参考答案：D 解析 ： 本题考查逻辑网络设计的相关知识。 逻辑网络设计应完成的主要设计包括网络结构的设计、物理层技术选择、局域网技术选 择与应用、广域网技术选择与应用、地址设计和命名模型、路由选择协议、网络管理方 案设计和网络安全方案设计。 采用10.H.X.Y/16的地址模式，每个机构可以用16位作为机构内的主机地址(去掉全0、 全1的地址)。 第28题：甲公司承接了乙公司的网络建设工作。由于待建网络规模很大，为确保建设工作顺 利进行，负责该项目的工程师在进行逻辑设计时提出了如下工作思路： ①明确逻辑设计工作的内容是：网络拓扑结构设计；物理层技术选择；局域网技术选择；广 域网技术选择；地址设计；路由协议选择；网络管理模式与工具选择；撰写逻辑设计文档。', '["A. 内容全面，符合逻辑设计的工作准则", "B. 应去掉物理层技术选择这一部分", "C. 应去掉路由协议选择这一部分", "D. 应增加网络安全设计这一部分"]', '', '', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'H.X.Y/16的模式分配，其中H为分支机构的序号(0表示公司总部，分支机构总数不会超过 200)。 对该工程师确定的逻辑设计内容的评价，恰当的是(27) 。 每个分支机构能连网的计算机的数量最多为(28)，配置IP地址时掩码是(29)。 参考答案：C 解析 ： 本题考查逻辑网络设计的相关知识。 逻辑网络设计应完成的主要设计包括网络结构的设计、物理层技术选择、局域网技术选 择与应用、广域网技术选择与应用、地址设计和命名模型、路由选择协议、网络管理方 案设计和网络安全方案设计。 采用10.n.X.Y/16的地址模式，每个机构可以用16位作为机构内的主机地址(去掉全0、 全1的地址)。 第29题：甲公司承接了乙公司的网络建设工作。由于待建网络规模很大，为确保建设工作顺 利进行，负责该项目的工程师在进行逻辑设计时提出了如下工作思路： ①明确逻辑设计工作的内容是：网络拓扑结构设计；物理层技术选择；局域网技术选择；广 域网技术选择；地址设计；路由协议选择；网络管理模式与工具选择；撰写逻辑设计文档。 ②在进行地址设计时，确定的方案是：按乙公司各分支机构的地理位置划分地址块，并按', '["A. 16", "B. 256", "C. 65534", "D. 65536"]', '', '', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'H.X.Y/16的模式分配，其中H为分支机构的序号(0表示公司总部，分支机构总数不会超过 200)。 对该工程师确定的逻辑设计内容的评价，恰当的是(27) 。 每个分支机构能连网的计算机的数量最多为(28)，配置IP地址时掩码是(29)。 参考答案：B 解析 ： 本题考查逻辑网络设计的相关知识。 逻辑网络设计应完成的主要设计包括网络结构的设计、物理层技术选择、局域网技术选', '["A. 255.0.0.0", "B. 255.255.0.0", "C. 255.255.255.0", "D. 255.255.240.0"]', '', '', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '75MB/S*2312/2346≈18.5MB/s。 第8题：对无线局域网，可显著提高数据率的技术是(7)，对有2台计算机、1个AP、采用 300Mbps的802.11n的WLAN，2台计算机数据传输的概率相同，则每台计算机实际传送用 户数据的最大理论速度最接近(8)MB/S。 参考答案：D 解析 ： 本题无线局域网(WLAN)的基本知识。 WLAN采用CSMA/CA访问控制方式，多台计算机竞争使用一个信道与AP通信以发送数 据，计算机越多，冲突的机会越多，每台计算机实际获得的发送数据的机会越少，这种 方式限制了一个AP可服务的计算机的数量即网络的规模。 MIMO方式利用多个天线，分别使用不同的信道(频率)，可同时传输更多的信号，使得 一台计算机与AP之间的数据率显著提高，也允许更多的计算机同时传输数据。 对于2台计算机、1个AP的情况，因发送概率相同，则每台机计算获得的实际数据率可 认为是总带宽的一半即150Mbps，换算成以字节为单位的数据率18.75MB/S。 此题可进一步精确：WLAN帧最大长度为2346B，其中数据部分最大长度为2312B，所 以每台计算机实际发送用户数据的最大理论速度的近似值可表示为', '["A. 1.4", "B. 6.7", "C. 9.3", "D. 18.7"]', '', '', 2, '2010年综合知识', '2010,综合知识', 2010);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '75MB/S*2312/2346≈18.5MB/s。 第9题：阻塞包 算法 (反馈抑制法)是一类典型的基于闭环控制原理的 拥塞控制 方法，其主要缺 点之一是(9)。 参考答案：B', '["A. 显著降低通信效率", "B. 可能导致不公平", "C. 不能真正控制拥塞", "D. 降低网络可用性"]', '', '', 2, '2010年综合知识', '2010,综合知识', 2010);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '1.10的 数据 分组，将被转发到的位置是(14)。', '["A. 2", "B. 2", "C. 2", "D. 2"]', '', '', 2, '2010年综合知识', '2010,综合知识', 2010);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '1.10的数据分组，将被转发到的位置是(14)。 参考答案：A 解析 ： 本题考查IP地址，特别是CIDR地址格式的基本知识。 CIDR(Classless Inter-Domain Routing)将IP地址看成两级结构，用“IP首地址/网络 前缀位数”的形式表示。在一个网络内表示主机的地址位数为32-网络前缀位数。全0和 全1的地址不能作为普通地址分配。 对于CIDR格式的IP地址，在进行路由选择时遵循的原则是最长匹配，即选择路由表中 网络前缀部分与分组中IP地址前缀部分的相同部分最长的那个地址作为转发地址。 第15题： IPv6 地址分为3级，其中第1级表示的含义是(15)。', '["A. 甲机构的网络", "B. 乙机构的网络", "C. 不确定", "D. 甲、乙之外的一个网络"]', '', '', 2, '2010年综合知识', '2010,综合知识', 2010);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '总结 一个标准的C类网络有8位(8bit)主机ID，—个最小的子网至少需要4个地址(主机ID全0 和全1的地址不能用于分配，剩余两个为主机号)，因此，一个标准的C类网络最多可划 分2 ÷4=64个子网。 第11题：一个IP 数据包 经过一台 路由器 转发到另一个 网络 ，该IP 数据包 的头部字段中一定会 发生变化的是(11)。', '["A. 源 IP", "B. 协议号", "C. 目的 IP", "D. TTL"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'TTL字段的作用 TTL是Time To Live的缩写，含义为“生存时间”。为避免因错误选路而产生的环路现 象(IP包在一个循环的路由中传递，永远到达不了目的地)。该字段定义了IP数据包可存 在的最大期限。由于确切的生存时间很难把握，该字段通常用跳跃站点数来度量，即当 数据包从一个网络传送到另一个网络时(即经过一个路由器的转发)，该字段的值减 1。当该字段为0时，数据包将被丢弃。 第12题：假定在一个 IPv4 网络 中只有两个主机HA和HB，HA和HB在同一个LAN内，并且没 有划分VLAN。如果HA和HB需要直接 通信 则需满足(12)。 参考答案：A 解析 ： 本题考查LAN、VLAN的概念、IP子网与物理网络的映射关系以及IP选路原理。 LAN是物理上的一个广播域，在LAN的所有设备都能收到其他设备的广播信息。 VLAN是逻辑上的广播域，可以把一个LAN划分为多个VLAN。划分VLAN后，LAN内的 设备以VLAN为单位组成广播域。 在IPv4网络中，一个IP子网只能映射一个LAN或VLAN;多个IPv4子网，可以映射到一个 LAN或VLAN中。 同一子网内主机可直接通信；不同子网之间，主机必须通过路由器才能进行通信。 第13题：假定一个 IPv4 网络 由4段不同的LAN互联而成，每段LAN上的最大MTU值分别是 512、1024、2048和4096，则在这个 IPv4 网络 上可能出现 IPv4 分组(IP Packet)的最大长度 是(13)。 参考答案：D 解析 ： 本题考查IPv4网络中MTU的概念和应用。 IPv4网络中，IPv4分组(即数据包)的理论最大长度为65535字节(参考试题11分析中的', '["A.  HA和HB必须在同一子网内", "B.  HA和HB必须在不同子网内", "C.  HA和HB无论在一个子网或不在一个子网都可以", "D.  HA和HB必须使用相同的操作系统"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '结论 一个稳定的RIP网络即为网络拓扑结构不再变化，路由表稳定，此时RIP分组30s广播一 次，路由老化周期为180s。如果每30分钟丢失一次路由器广播UDP报文，则不会对路 由器和网络产生任何影响。 第15题：在一个 子网 中有一个主机HA和 路由器 RX，HB是其他 子网 的主机。在主机HA中到 HB的路由是RX(HA经RX到达HB)。假定在HA和RX的 子网 中再增加一个 路由器 RY，想让HA 经RY到达HB，此时需要(15). 参考答案：B 解析 ： 本题重点考查ICMP协议中路由重定向的概念。 Internet网络中的设备可分为路由器和主机两种，在路由器和主机中都需要具有正确的 路由表网络才能正常的工作。 在Internet中，路由信息的传输分为两种：一种是路由器和主机之间的路由信息传递， 它是由ICMP的路由功能完成的；另一种是路由器和路由器之间路由信息的交换，它们 要依靠特殊的协议来完成，这些特殊的协议就是路由协议。无论ICMP协议还是路由协 议，最终要在各自的结点上(包括主机和路由器)维护一个正确的路由表，以路由表决定 如何发送(针对主机)和转发(针对路由器)IP分组。 ICMP的路由功能包括两个功能：一是发现本地路由器；二是路由重定向。下图显示了 ICMP报文的路由器广告报文格式(类型=9)。 路由器广告报文包含路由器地址列表以及优先级选择级别。ICMP报文给出了类型值为 9，代码字段为空，表中地址总数和每个表项的大小以及路由器声明的“有效时间”。', '["A.  RY发送路由重定向ICMP报文给HA", "B.  RX发送路由重定向ICMP报文给HA", "C.  RY发送路由重定向ICMP报文给HB", "D.  RX发送路由重定向ICMP报文给HB"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '半打开连接和半关闭连接的概念 TCP连接经三次握手建立后，如果一方已经关闭或异常终止连接而另一方却还不知道， 我们称这样的TCP连接为半打开(half-open)连接。任何一端的主机异常都可能导致发生 这种情况。只要不打算在半打开连接上传输数据，仍处于连接状态的一方就不会检测另 一方已经出现异常。TCP的Keepalive定时器用于发现并结束半打开连接。 TCP连接建立后，TCP提供了双向的数据通路。TCP提供了其中一端结束它的发送后还 能接收来自另一端数据的能力，这称为半关闭。半关闭是TCP连接关闭过程中完成了前 半部分的状态，这时只关闭了一个方向上的数据通道，另一个方向上仍然能够继续数据 传输。 第18题： IPv6 与 IPv4 相比，下列叙述正确的是(18)。 参考答案：D 解析 ：', '["A.  IPv6地址也分为A、B、C、D、E 五类", "B. IPv6网络可直接使用IPv4的路由协议", "C. IPv6不能实现地址自动配置", "D. IPv6分组的头中增加了流标签(Flow Label)字段"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'IMAP4协议 IMAP revl(RFC2060)是Internet Message Access Protocol的缩写，是通过Internet 获取信息的一种协议。IMAP4是IMAP协议的第4个版本，正如POP3是POP协议的第3 个版本一样。IMAP是一种强有力的邮箱访问方式。 POP3提供了快捷的邮件下载服务，用户可以利用POP3把邮箱里的信下载到PC上进行 离线阅读。一旦邮件进入PC的本地硬盘，就可以选择把邮件从服务器上删除，然后脱 离与Internet的连接并选择在任何时候阅读已经下载的邮件。 IMAP支持用户在线阅读功能，支持Web Mail功能(不下载到本地，所有邮件都在邮件 服务器上)，允许用户在服务器上建立任意层次结构的文件夹，并且可以灵活地在文件 夹之间移动邮件，随心所欲地组织你的邮箱。当然，IMAP也支持邮件下载到本地阅读 (等同POP3功能) 第21题：在 互联网 上，当我们访问一个设备时，(21)。', '["A. 必须要有域名，才能访问", "B. 有IP地址就可以访问", "C. 必须同时有IP地址和域名", "D. 必须要有域名服务器"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '结论 一个稳定的OSPF单区域网络，网络的拓扑结构稳定，即LSDB中的链路不发生变化，此 时所有的路由器中的LSDB都相同。 第23题：下列对 FTP 业务的描述正确的是(23)。 参考答案：B 解析 ： 本题考查对数据业务的理解和对FTP业务的访问机制的理解。 FTP业务属于文件传输类的数据业务。针对Internet网络而言，文件传输要保证可靠性 (文件传输不能有差错)，对实时性要求不高(可以有大的延迟或延迟抖动)。因此FTP业务 是基于TCP协议而实现的。 FTP在用户下载时需要提供用户名的口令；即使是匿名登录，其实本质上也是有用户名 (anonymous)和口令(任意邮箱格式 xxx@xx.xxx )。 第24题：下列对集成服务(IntServ)模型和区分服务(DiffServ)模型描述正确的是(24)。', '["A.  FTP服务必须通过用户名和口令才能访问。FTP可以基于UDP或TCP传输信息", "B.  FTP服务器必须通过用户名和口令才能访问。FTP只能基于TCP传输信息", "C.  FTP服务器无须用户名和口令即可访问。FTP可以基于UDP或TCP传输信息", "D.  FTP服务器无须用户名和口令即可访问。FTP只能基于UDP传输信息"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '综合业务模型和分类业务模型的结合 这两种技术可以统合起来形成支持QoS敏感(aware)型IP业务的网络模型。在IETF给出 的框架中，端到端的QoS是由网络边缘的IntServ区域与网络核心的DiffServ区域—起提 供的，这一方式常被称为“核心边缘”方式。 第25题：MPLS是一种将(25) 路由 结合起来的集成宽带 网络技术 。 第二层转发和第三层 参考答案：B 解析 ： 本题考查对MPLS技术核心思想的理解。 MPLS最初是基于ATM技术发展起来的。它结合ATM技术和IP技术各自的优点。其核心 思想是：边缘路由，核心交换。从协议层次上来观察即为：结合了第二层转发和第三层 路由的集成宽带网络技术。 第26题：在一个 局域网 上，进行 IPv4 动态地址自动配置的 协议 是 DHCP 协议 。 DHCP 协议 可 以动态配置的信息是(26)。', '["A. 第一层转发和第二层", "B.", "C. 第三层转发和第四层", "D. 第四层转发和第七层"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '1000Mbps共享式以太网 如果使用共享式1000Mbps以太网(通信介质UTPcat5)组网，只能使用一个中继器。单 段连网(不使用连网设备)距离为100m。则最大联网距离为200m。 实际上，1000Mbps铜线以太网，一般使用超5类和6类UTP作为通信介质。', '["A.  MAC地址", "B.  CSMA/CD", "C. 通信介质", "D. 网桥协议"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '网桥协议的问题和连网距离 STA运行需要二层设备不断交换链路信息(物理连接的信息)，其有信息广播的周期和 STA算法收敛速度的问题。如果用二层设备组网的规模过大，信息传播和算法收敛将变 的不可预测。按经验原则(无理论证明)，一般二层设备组网最大可到7级左右(7个二层设 备级联)。 第31题：VLAN实施的前提条件是(31)。 参考答案：C 解析 ： 本题考查VLAN的概念和实现基础。 VLAN是在二层实现的，是基于二层交换设备实现的。在普通的网桥上(非交换式)将无 法实现VLAN。 第32题：在 以太网 半双工 共享式连接中，我们无需流量控制；而在 全双工 交换式连接中要考 虑流量控制，其原因是(32)。', '["A.  使用CSMA/CD协议", "B. 基于二层设备实现", "C. 基于二层交换机实现", "D. 基于路由器实现"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '252.0。 第35题：应用MPLS VPN 时，针对每个 VPN 地址规划应满足的条件是(35)。不同的 VPN 信息 通过MPLS 骨干网 (或核心网)时通过(36)进行区分。 参考答案：A 解析 ： 本题考查VPN的概念和MPLS VPN的工作原理。', '["A. 每个VPN都是独立的，可以使用任何地址，只要保证在VPN内部合法正确即可", "B. VPN之间的地址不能相互重叠", "C. VPN内只能使用公网IP地址", "D. VPN内只能使用私网IP地址"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '结论 VPN是用户的专用网络，因此每个VPN是独立的。如果每个VPN是独立的，就存在地 址重叠问题，即两个或多个VPN内部的地址信息是重叠的，此时只传递VPN内部的路由 信息就无法正常进行选路。 要在存在地址重叠的MPLS三层VPN的MPLS骨干(或称核心)网上正确传递VPN路由，就 必须传递两个信息：VPN内部的路由信息(用IP地址标识)和VPN的标识，其中VPN标识 用于PE之间识别要传递到那些VPN，IP地址(包括子网标识)用于传递VPN内部的路由信 息。 第36题：应用MPLS VPN时，针对每个VPN地址规划应满足的条件是(35)。不同的VPN信息 通过MPLS骨干网(或核心网)时通过(36)进行区分。', '["A.  IP地址+AS号", "B. IP地址+子网掩码", "C. VPN标识符", "D. VPN标识符+IP地址"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '结论 VPN是用户的专用网络，因此每个VPN是独立的。如果每个VPN是独立的，就存在地 址重叠问题，即两个或多个VPN内部的地址信息是重叠的，此时只传递VPN内部的路由', '["A. 从乙用户所在的物理网络的物理层开始检查故障，依次检测物理层、数据链路层、网", "B. 从乙用户所在的物理网络的路由器开始检查故障，依次检测路由器，二层交换机、中", "C. 从检测公司的服务器开始，依次检测服务器、网络互联设备、物理层连接", "D. 从甲用户所在的物理网络首先开始检测，依次检测物理层、数据链路层、网络层直到"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '与具体互联网业务相结合。 E-mail：发送邮件和接收邮件。视为对等流量，即50%流出，50%流入。 Web：浏览网络，从web下载的流量大。使用20/80法则。流出：20%，流入80%。 本题答案：流出流量：30×1×50%+30×0.5×20%=18Mbps。 第39题：在采用公开 密钥 密码体制 的 数字签名 方案中，每个用户有一个 私钥 ，可用它进行 (39)；同时每个用户还有一个 公钥 ，可用于(40)。 参考答案：B 解析 ： 本题考查公开密钥密码体制的基础知识。 与只使用一个密钥的对称传统密码不同，公钥密码学是非对称的，它依赖于一个公开密 钥和一个与之在数学函数上相关但不相同的私钥。由于公钥可以对外公开，通常用于加 密和签名认证(这样与之通信的多个用户可以共用一个加密密钥，密钥管理开销小)，私 钥是用户自己保管的，通常用于解密和签名。', '["A. 解密和验证", "B. 解密和签名", "C. 加密和签名", "D. 加密和验证"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '7，业务发展差的概率为0.3。现有三种规划方案可供选择： 方案1，直接投资3000万元大规模建网。若业务发展得好，每年可获利1000万元，若业务发 展不好，每年亏损200万元，服务期为10年； 方案2，投资1400万元建设小规模 网络 。若业务发展得好，每年可获利400万元，若业务发展 不好，每年仍可获利300万元，服务期为10年； 方案3，前3年按方案2实施，即先投资1400万元建设小规模 网络 ， 收益 同方案2。3年后若业 务发展不好，则继续按方案2实施；若业务发展得好，则再追加投资2000万元进行 网络 扩 容，扩容后服务期为7年，每年可获利950万元。 根据以上条件经计算可知(70)。 参考答案：B 解析 ： 本题考查风险型决策方法和概率相关的基础知识。 在风险型决策问题中，各种方案的实施在不同的条件下所导致的后果是不一样的，而各 种条件和后果出现的概率是可以测算的，决策者可以通过计算出各方案在不同条件下的 期望收益来考虑未来的经济效果。针对本题分别计算三种方案的期望净收益，期望净收 益最大的为最优方案。 该方案1的期望净收益为：', '["A. 方案1的期望净收益为5000万元", "B. 方案3的期望净收益为3595万元", "C. 方案1为最优方案", "D. 方案2为最优方案"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '7×(400×3-2000+950*7)+0.3×300×10-1400=3595(万元)。 计算结果表明，方案3的期望净收益最大，因此，方案3为最优方案。 第71题：A glue that holds the whole Internet together is the network layer protocol, (71) . Unlike most older network layer protocols, it was designed from the beginning with internetworking in mind. Its job is to provide a (72) way to transport datagrams from source to destination, without regard to whether these machines are on the same network or whether there are other networks in between them. Communication in the Internet works as follows. The (73) layer takes data streams and breaks them up into datagrams. Each datagram is transmitted through the Internet, possibly being fragmented into smaller units as it goes. When all the pieces finally get to the destination machine, they are reassembled by the (74) layer into the original datagram. This datagram is then handed to the transport layer, which inserts it into the receiving process’ input stream. An IP datagram consists of a header part and a text part. The header has a (75) part and a variable length optional part. 参考答案：A 解析 ： 将整个互联网连成一体的是网络层协议(71)。与大多数更早的网络层协议不同,它在设计 之初就充分考虑了网络互连。它负责提供一种(72)的方式，从信源到信宿传递数据报， 不管信源和信宿机器是否在同一个网络中，或者它们之间是否有其他网络。互联网中的 通信遵照以下方式进行。(73)层将数据流分割成数据报，每个数据报通过互联网传输的 过程中，有可能被分割成更小的单元。当所有的数据单元最终到达目的地主机时，它们 被(74)层重新组合成原始数据报。这个数据报随后被提交给传输层，由传输层将其插入 接收进程的输入流中。一个IP数据报包含报头和报文两部分。报头包括一个(75)部分和 一个可变长度的可选部分。 第72题：A glue that holds the whole Internet together is the network layer protocol, (71) . Unlike most older network layer protocols, it was designed from the beginning with internetworking in mind. Its job is to provide a (72) way to transport datagrams from source to destination, without regard to whether these machines are on the same network or whether there are other networks in between them.', '["A. IP (Internet Protocol)", "B. IP (Interworking Protocol)", "C.  TCP (Transport Control Protocol)", "D.  TCP (Transfer Communication Protocol)"]', '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0.0的路径，结果导致目标地址为10.4.0.0的数据包在三个路由器之间来回传递，从 而形成路由环路，直到路由度量达到最大值才能发现网络故障。 解决路由环路问题可以采用水平分割法（Split Horizon)。这种方法规定，路由器必须 有选择地将路由表中的信息发送给邻居，而不是发送整个路由表。具体地说，一条路由 信息不会被发送给该信息的来源。可以对上图中R2的路由表项将加上一些注释，这样， 每一条路由信息都不会通过其来源接口向回发送，就可以避免环路的产生。', '["A. OSPF是一种应用于不同自治系统之间外部网关协议", "B. OSPF是基于相邻结点的负载来计算最佳路由", "C. 在OSPF网络中，不能根据网络的操作状态动态改变路由", "D. 在OSPF网络中，根据链路状态算法确定最佳路由"]', '', '', 2, '2012年综合知识', '2012,综合知识', 2012);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '133.0/24，如果进行 路由 汇聚，能覆盖这4条 路由 的地址是（37)。 参考答案：A 解析 ： 地址172.118.129.0/24的二进制形式为 10101100 01110110 10000001 00000000 地址172.118.130.0/24的二进制形式为 10101100 01110110 10000010 00000000 地址172.118.132.0/24的二进制形式为 10101100 01110110 10000100 00000000 地址172.118.133.0/24的二进制形式为 10101100 01110110 10000101 00000000 地址172.118.128.0/21的二进制形式为 10101100 01110110 10000000 00000000 所以能覆盖这4条路由的地址是172.118.128.0/21 。 第38题：属于 网络', '["A. 172.118.128.0/21", "B. 172.118.128.0/22", "C. 172.118.130.0/22", "D. 172.118.132.0/20"]', '', '', 2, '2012年综合知识', '2012,综合知识', 2012);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '200.0/21的地址是（38) 参考答案：B 解析 ： 地址202.117.200.0/21的二进制形式为：11001010011101011100100000000000 。', '["A. 202.117.198.0", "B. 202.117.206.0", "C. 202.117.217.0", "D. 202.117.224.0"]', '', '', 2, '2012年综合知识', '2012,综合知识', 2012);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '224.0的二进制形式为：11001010011101011110000000000000。 可以看出202.117.206.0属于网络202.117.200.0/21 。 第39题：下面的地址中，属于 单播 地址的是（39)。', '["A. 172.31.128.255/18", "B. 10.255.255.255", "C. 172.160.24.59/30", "D. 224.105.5.211"]', '', '', 2, '2012年综合知识', '2012,综合知识', 2012);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '5G系统能够提供3G系统中才有的一些功能，例如分组交换业务，也能共享2G时代开发 出来的TDMA或CDMA网络。GPRS分组网络重叠在GSM网络之上，利用GSM网络中未 使用的TDMA信道，为用户提供中等速度的移动数据业务。 GPRS是基于分组交换的技术，多个用户可以共享带宽，每个用户只有在传输数据时才会 占用信道，所有的可用带宽可以立即分配给当前发送数据的用户，适合于Web浏览、E- mail收发和即时消息那样的共享带宽的间歇性数据传输业务。通常，GPRS系统是按交换 的字节数计费，而不是连接时间计费。GPRS系统支持IP协议和PPP协议。理论上的分组 交换速度大约是170kb/s,而实际速度只有30?70kb/s。 对GPRS的射频部分进行改进的技术方案称为增强数据速率的GSM演进 (Enhanced Datarates for GSM Evolution,EDGE)。EDGE又称为增强型 GPRS(EGPRS：" ,可以工作在已经部署GPRS的网络上，只需要对手机和基站设备做一些 简单的升级。EDGE被认为是2.75G技术，采用8PSK的调制方式代替了GSM使用的高斯最 小移位键控（GMSK)调制方式，使得一个码元可以表示3比特信息。理论上说，EDGE提 供的数据速率是GSM系统的3倍。2003年EDGE被引入北美的GSM网络，支持从20? 200kb/s的高速数据传输，最大数据速率取决于同时分配到的TDMA帧的时隙的多少。 第23题：IEEE802.3规定的CSMA/CD 协议 可以利用多种监听 算法 来减小发送 冲突 的概率，下面 关于各种监听 算法 的描述中，正确的是（23)。 参考答案：D 解析 ： 以太网的监听算法分为3种： 非坚持型监听算法可以最大限度地减少冲突概率，但是可能会延迟发送，引起带宽的浪 费；坚持型监听算法能及时抢占信道，但是会增加冲突的概率。P-坚持型监听算法既可以', '["A. 非坚持型监听算法有利于减少网络空闲时间", "B. 坚持型监听算法有利于减少冲突的概率", "C. P 坚持型监听算法无法减少网络的空闲时间", "D. 坚持型监听算法能够及时抢占信道"]', '', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '停止系统服务中的（31)服务。 参考答案：C 解析 ： 本题考查DNS服务器及其原理。 当DNS服务器更新了某域名的IP地址后，客户端可能由于缓存中的域名记录尚未更新，无 法访问网站，此时可以通过命令ipconfig/flushdns或停止服务DNSClient来更新。 第31题：如果DNS服务器更新了某域名的IP地址，造成客户端无法访问网站，在客户端通常有 两种方法解决此问题：', '["A. nslookup", "B. ipconfig/renew", "C. ipconfig/flushdns", "D. ipconfig/release"]', '', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '停止系统服务中的（31)服务。 参考答案：B 解析 ： 本题考查DNS服务器及其原理。 当DNS服务器更新了某域名的IP地址后，客户端可能由于缓存中的域名记录尚未更新，无 法访问网站，此时可以通过命令ipconfig/flushdns或停止服务DNS Client来更新。', '["A.  SNMP Client", "B.  DNS Client", "C. Plug and Play", "D.  Remote Procedure Call (RPC)"]', '', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '01000011.00100001的 数据报 ，则该 数据报 应送给用户（38)。 参考答案：D 解析 ： 用户U1有4000台主机，则必须给他分配16个C类网络（256X16)，则指定给U1的地址掩 码应为255.255.240.0。 给用户U2分配的C类网络号为196.25.16.0?196.25.31.0,其中包含16八C类网络，所以用 户U2的地址掩码应为255.255.240.0。 用户U1的网络地址196.25.64.0/20：11000100.00011001.01000000.00000000 用户U2的网络地址196.25.64.0/20：11000100.00011001.00100000.00000000 路由器收到的数据报目标地址为： 11000100.00011001.01000011.00100001 根据最长匹配原则，该数据报应送给用户U1。 第36题：采用可变长子网掩码可以把大的网络划分成小的子网，或者把小的网络汇聚成大的超 网。假设用户U1有4000台主机，则必须给他分配（35)个C类网络，如果分配给用户U1的超网 号为196.25.64.0,则指定给U1的地址掩码为（36);假设给用户U2分配的C类网络号为', '["A. 4", "B. 8", "C. 10", "D. 16"]', '', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '01000011.00100001的数据报，则该数据报应送给用户（38)。 参考答案：D', '["A. 255.255.255.0", "B. 255.255.250.0", "C. 255.255.248.0", "D. 255.255.240.0"]', '', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '01000011.00100001的数据报，则该数据报应送给用户（38)。 参考答案：D 解析 ： 用户U1有4000台主机，则必须给他分配16个C类网络（256X16)，则指定给U1的地址掩 码应为255.255.240.0。 给用户U2分配的C类网络号为196.25.16.0?196.25.31.0,其中包含16八C类网络，所以用 户U2的地址掩码应为255.255.240.0。 用户U1的网络地址196.25.64.0/20：11000100.00011001.01000000.00000000 用户U2的网络地址196.25.64.0/20：11000100.00011001.00100000.00000000 路由器收到的数据报目标地址为： 11000100.00011001.01000011.00100001 根据最长匹配原则，该数据报应送给用户U1。 第38题：采用可变长子网掩码可以把大的网络划分成小的子网，或者把小的网络汇聚成大的超 网。假设用户U1有4000台主机，则必须给他分配（35)个C类网络，如果分配给用户U1的超网 号为196.25.64.0,则指定给U1的地址掩码为（36);假设给用户U2分配的C类网络号为', '["A. 255.255.255.0", "B. 255.255.250.0", "C. 255.255.248.0", "D. 255.255.240.0"]', '', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '01000011.00100001的数据报，则该数据报应送给用户（38)。', '["A. U1", "B. U2", "C. U1或U2", "D. 不可到达"]', '', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '10.1的WWW服务”的是 (41)。 access-list 101 permit tcp any host 202.110.10.1 eq www 参考答案：B 解析 ： 本题考查ACL语句。 正确的ACL语句为：access-list 101 permit tcp any host 202.110.10.1 eq www。 第42题： SSL 协议 共有上下两层组成，处于下层的是（42)。 参考答案：D', '["A. access-list 101 permit any 202.110.10.1", "B.", "C. access-list 101 deny any 202.110.10.1", "D. access-list 101 deny tcp any host 202.110.10.1 eq www"]', '', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '11b工作在2.4G频段、最高速率11兆、目前已经逐步被淘汰；802.11g工作在2.4G频 段、最髙速率54兆；802.11n工作在2.4GHz或者5GHz、最高速率可达600兆。因此 IEEE802.11b/g/n，采用的共同工作频带为2.4GHz。 第65题：在进行无线WLAN网络建设时，现在经常使用的协议是IEEE 802.11b/g/n，采用的共 同工作频带为（64)。其中为了防止无线信号之间的干扰，IEEE将频段分为13个信道，其中仅有 三个信道是完全不覆盖的，它们分别是（65)。', '["A. 信道1、6和13", "B. 信道1、7和11", "C. 信道1、7和13", "D. 信道1、6和11"]', '', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '16.0/24到172.30.31.0/24的分组通过 路由器 ，则对应 ACL语句应该是（ ）。 参考答案：C 解析 ： 如果允许来自子网172.30.16.0/24到172.30.31.0/24的分组通过路由器，则对应的ACL 语句应该是access-list 10 permit 172.30.16.0 0.0.15.255。值得注意的是反掩码', '["A. access-list 10 permit 172.30.16. 0 255.255. 0.0", "B. access-list 10 permit 172.30.16. 0 0.0.255.255", "C. access-list 10 permit 172.30.16. 0 0.0.15.255", "D. access-list 10 permit 172.30.16. 0 255.255.240.0"]', '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '15.255正好覆盖了172.30.16.0网络中最后12位表示的全部地址。 第24题：结构化布线系统分为六个 子系统 ，其中水平 子系统 （ ）。 参考答案：B 解析 ： 结构化布线系统分为6个子系统：工作区子系统、水平子系统、管理子系统、干线 (或垂 直）子系统、设备间子系统和建筑群子系统。其中水平子系统是指各个楼层接线间的配', '["A. 由各种交叉连接设备以及集线器和交换机等交换设备组成", "B. 连接干线子系统和工作区子系统", "C. 由终端设备到信息插座的整个区域组成", "D. 实现各楼层设备间子系统之间的互连"]', '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '133.0/24，如果进行 路由 汇聚，能覆盖这4条 路由 的地址是（ ）。 参考答案：A 解析 ： 展开IP地址的第3字节如下： 第1条路由：10000001 第2条路由：10000010 第3条路由：10000100 第4条路由：10000101 聚合之后该字节前5比特网络号，后3比特主机号，即网络号210.114.128.0,掩码长度21 位。 第38题：下面地址中属于 单播 地址的是（ ）。 参考答案：C 解析 ： 下面4个网络地址的二进制形式是 (1)125.221.191.255/18 01111101 .11011101 .10111111.11111111 (2)192.168.24.123/30 11000000.10101000.00011000.01111011 (3)200.114.207.94/27 11001000.01110010.11001111.01011110', '["A. 210.114.128.0/21", "B. 210.114.128.0/22", "C. 210.114.130.0/22", "D. 210.114.132.0/20"]', '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '17.255/22是什么地址？（ ）。 参考答案：C 解析 ： IP地址202.117.17.255/22 的二进制形式是', '["A. 网络地址", "B. 全局广播地址", "C. 主机地址", "D. 定向广播地址"]', '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '000100,主机号是01.11111111。 第40题： IPv6 地址的格式前缀用于表示地址类型或 子网 地址，例如60位的地址前缀 10DE00000000CD3有多种合法的表示形式，以下选项中，不合法的是（ ）。 参考答案：C 解析 ： 以上IPv6地址前缀中不合法的是10DE:0:0:CD3/60，因为这种表示可展开为 10DE:0000:0000:0000:0000:0000:0000:0CD3，另外CD30也变成了0CD3,这些都是 错误的。 第41题：下列 攻击 方式中，（ ）不是利用TCP/IP漏洞发起的 攻击 。', '["A.  10DE:0000: 0000:CD30: 0000:0000:0000:000/60", "B.  10DE::CD30:0:0:0:0/60", "C.  10DE: 0:0:CD3/60", "D.  10DE: 0:0:CD3::/60"]', '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '4GHz频段划分出13个信道，而这13个信道中有相互覆盖和相互重叠的情况，为了无 线网络能够互不干扰的工作，在13个信道中，只有3个信道可用，1、6、11号信道。 第56题：目前大部分 光缆 工程 测试 都采用OTDR（光时域反射计）进行 光纤 衰减的 测试 ， OTDR通过检测来自 光纤 的背向散射光进行 测试 。这种情况下采用（ ）方法比较合适。', '["A. 双向测试", "B. 单向测试", "C. 环形测试", "D. 水平测试"]', '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '5E07.FFFF。', '["A. R1与R2、R3的物理链路连接不稳定", "B. R1未能完整的学习到R2和R3的局域网路由", "C. 管理员手工地对R2和R3进行了路由汇总", "D. RIP协议版本配置错误，RIPv1不支持不连续子网"]', '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '3.0/24路由进行了路由汇总，统一汇总成172.16.0.0/16路由，因此，当从R1 ping R2或者R3时，路由器认为从R1与R2和R3相连的接口均可到达，实现了不恰当的 负 载均衡。 第65题：使用长度1518字节的帧 测试 网络吞吐量时，1000M 以太网 抽样 测试 平均值是（ ） 时，该 网络设计 是合理的。', '["A. 99%", "B. 80%", "C. 60%", "D. 40%"]', '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '5/125μm多模光纤的最大传输距离为220m，使用50/125μm多模光纤的域大传输 距离为500 米。因此只需要将两栋楼之间的多模光纤更换为50/125μm多模光纤即可。 第67题：IANA在可聚合全球 单播 地址 范围 内指定了一个格式前缀来表示 IPv6 的6to4地址， 该前缀为（ ）。 参考答案：C 解析 ：', '["A. 0x1001", "B. 0x1002", "C. 0x2002", "D. 0x2001"]', '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '832。 第10题：软件设计师王某在其公司的某一综合 信息管理系统 软件开发 项目中、承担了大部分 程序设计 工作。该系统交付用户，投入试运行后，王某辞职离开公司，并带走了该综合 信息 管理系统 的 源程序 ，拒不交还公司。王某认为综合 信息管理系统 源是他独立完成的，他是综 合 信息管理系统 源程序 的 软件著作权人 。王某的行为（10）。 参考答案：A 解析 ： 本题考查知识产权基本知识。 《计算机软件保护条例》第13条规定“自然人在法人或者其他组织中任职期间所开发的 软件有下列情形之一的，该软件著作权由该法人或者其他组织享有，该法人或者其他组 织可以对开发软件的自然人进行奖励： (一)针对本职工作中明确指定的开发目标所开发的软件； (二)开发的软件是从事本职工作活动所预见的结果或者自然的结果； (三)主要使用了法人或者其他组织的资金、专用设备、未公开的专门信息等物质技术条 件所开发并由法人或者其他组织承担责任的软件。” 根据《计算机软件保护条例》规定，可以得出这样的结论，当公民作为某单位的职工 时，如果其开发的软件属于执行本职工作的结果，该软件著作权应当归单位享有。而荜 位可以给予开发软件的职工奖励。需要注意的是，奖励软件开发者并不是单位的一种法 定义务，软件开发者不可援引《计算机软件保护条例》强迫单位对自己进行奖励。 王某作为公司的职员，完成的某一综合信息管理系统软件是针对其本职工作中明确指定', '["A. 侵犯了公司的软件著作权", "B. 未侵犯公司的软件著作权", "C. 侵犯了公司的商业秘密权", "D. 不涉及侵犯公司的软件著作权"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '记账(Accounting):记录用户使用网络资源的情况。 通常用来实现AAA服务的协议是RADIUS(Remote Authentication Dial In User Service)协议，这是基于UDP的一种客户机/服务器协议。RADIUS客户机是网络访问服 务器，它通常是一个路由器、交换机或无线访问点。RADIUS服务器通常是在UNIX或 Windows 2000服务器上运行的一个监护程序。 第22题：AAA服务器（AAA server）是一种处理用户访问请求的框架协议，它主要功能有3 个，但是不包括（21），通常用来实现AAA服务的协议是（22）。 参考答案：B 解析 ： AAA服务器的主要目的是管理用户访问网络服务器权限，具体为：', '["A. Kerberos", "B.  RADIUS", "C. SSL", "D. IPSec"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '记账(Accounting):记录用户使用网络资源的情况。 通常用来实现AAA服务的协议是RADIUS(Remote Authentication Dial In User Service)协议，这是基于UDP的一种客户机/服务器协议。RADIUS客户机是网络访问服 务器，它通常是一个路由器、交换机或无线访问点。RADIUS服务器通常是在UNIX或 Windows 2000服务器上运行的一个监护程序。 第23题：由无线终端组成的MANET 网络 ，与固定 局域网 最主要的区别是（23），在下图所 示的由A、B、C三个结点组成的MANET中，圆圈表示每个结点的发送 范围 ，结点A和结点C 同时发送 数据 ，如果结点B不能正常接收，这时结点C称为结点A的（24）。 参考答案：D 解析 ： IEEE802.il标准定义的AdHoc网络是由无线移动结点组成的对等网，无须网络基础设施 的支持，能够根据通信环境的变化实现动态重构，提供基于多跳无线连接的分组数据传 输服务。在这种网络中，每一个结点既是主机，又是路由器，它们之间相互转发分组， 形成一种自组织的MANET(Mobile Ad Hoc Network)网络。 与传统的有线网络相比，MANET有如下特点： ?网络拓扑结构是动态变化的，由于无线终端的频繁移动，可能导致结点之间的相互位 置和连接关系难以维持稳定。 ?无线信道提供的带宽较小，而信号衰落和噪声干扰的影响却很大。由于各个终端信号 覆盖范围的差别，或者地形地物的影响，还可能存在单向信道。 ?无线终端携带的电源能量有限，应采用最节能的工作方式，因而要尽量减小网络通信 开销，并根据通信距离的变化随时调整发射功率。 ?由于无线链路的开放性，容易招致网络窃听、欺骗、拒绝服务等恶意攻击的威胁，所 以需要特别的安全防护措施。 路由算法是MANET网络中重要的组成部分，由于上述特殊性，传统有线网络的路由协 议不能直接应用于MANET。IETF成立的MANET工作组开发了MANET路由规范，使其 能够支持包含上百个路由器的自组织网络，并在此基础上开发支持其他功能的路由协', '["A. 无线访问方式可以排除大部分网络入侵", "B. 不需要运行路由协议就可以互相传送数据", "C. 无线信道可以提供更大的宽带", "D. 传统的路由协议不适合无线终端之间的通信"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '5.40：1101 1100.0111 0011.0000 0101.0010 1000 第38题：主机地址122.34.2.160属于 子网 （38）。 参考答案：C', '["A. 122.34.2.64/26", "B. 122.34.2.96/26", "C. 122.34.2.128/26", "D. 122.34.2.192/26"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '选择e，使e×d=1(mod z) 明文P被分成k位的块，k是满足2 k <n的最大整数，于是有0≤P<n。加密时计算 C=P e (mod n) 这样公钥为(e，n)。解密时计算 P=C d (mod n) 即私钥为(d，n)。 第42题：按照RSA算法，取两个最大素数p和q，n=p*q，令φ(n)=(p-1)*(q-1)，取与φ(n)互 质的数e，d=e - mod φ(n)，如果用M表示消息，用C表示密文，下面（41）是加密过程， （42）是解密过程。', '["A.  M=C", "B.  M=C", "C.  M=C", "D.  M=C"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '选择e，使e×d=1(mod z) 明文P被分成k位的块，k是满足2k<n的最大整数，于是有0≤P<n。加密时计算 C=P e (mod n) 这样公钥为(e，n)。解密时计算 P=C d (mod n) 即私钥为(d，n)。 第43题：A和B分别从CA1和CA2两个认证中心获取了自己的证书IA和IB，要使A能够对B进行 认证，还需要（43）。 参考答案：C 解析 ： 本题考查CA数字证书认证的基础知识。 CA为用户产生的证书应具有以下特性。 ①只要得到CA的公钥，就能由此得到CA为用户签署的公钥。 ②除CA外，其他任何人员都不能以不被察觉的方式修改证书的内容。 如果所有用户都由同一CA签署证书，则这一CA就必须取得所有用户的信任。如果用户 数量很多，仅一个CA负责为所有用户签署证书就可能不现实。通常应有多个CA，每个', '["A.  A和B交换各自公钥", "B.  A和B交换各自私钥", "C.  CA1和CA2交换各自公钥", "D.  CA1和CA2交换各自私钥"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '240.0，那么地址的范围是：202.117.0.0——202.117.15.254。 第28题：某网络的地址是202.117.0.0，其中包含4000台主机，指定给该网络的合理子网掩码是 （27） ，下面选项中，不属于这个网络的地址是（28）。 参考答案：D 解析 ：', '["A. 202.117.0.1", "B. 202.117.1.254", "C. 202.117.15.2", "D. 202.117.16.113"]', '', '', 2, '2016年综合知识', '2016,综合知识', 2016);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '240.0，那么地址的范围是：202.117.0.0——202.117.15.254。 第29题：在大型 网络 中，为了有效减少 收敛时间 ，可以采用的 路由协议 配置方法是（29）。 参考答案：A 解析 ： 存根网络是一种通过单一路由访问的网络。是指与外界只有一个输出连接的网络，在存根网 络里面，可以使用默认路由。可以有效减少收敛时间。 第30题：浏览网页时 浏览器 与Web 服务器 之间需要建立一条TCP连接，该连接中 客户端 使用的 端口 是（30）。 参考答案：D 解析 ： 浏览网页时浏览器与Web服务器之间需要建立一条TCP连接，该连接中客户端使用的端口是 1024——65535。 第31题：DNS资源记录（31）定义了区域的 反向搜索 。 参考答案：B', '["A. 为存根网络配置静态路由", "B. 增加路由器的内存和处理能力", "C. 所有路由器都配置成静态路由", "D. 减少路由器之间的跳步数"]', '', '', 2, '2016年综合知识', '2016,综合知识', 2016);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '133.0/24，在 路由器 中汇聚成一条路由，该路由的 网络地址 是（ ）。 参考答案：A 第31题：以下关于在 IPv6 中任意播地址的叙述中，错误的是（ ）。 参考答案：C 解析 ： 任意播地址是一个标识符对应多个接口的情况。如果一个数据报文要求被传送到一个任意点 地址，则将被传送到最近一个接口（路由器决定）。 第32题：RIPv2对RIPv1 协议 的改进之一是采用 水平分割法 。以下关于 水平分割法 的说法中错误的 是（ ）。 参考答案：D', '["A. 202.114.128.0/21", "B. 202.114.128.0/22", "C. 202.114.130.0/22", "D. 202.114.132.0/20"]', '', '', 2, '2017年综合知识', '2017,综合知识', 2017);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '采用测试软件输入网站 www.xxx.com/index.action. 执行ifconfig 命令，结果如图3-2所示。', '["A. Java反序列化", "B. 跨站脚本攻击", "C. 远程命令执行", "D. SQL 注入"]', '', '', 2, '2017年综合知识', '2017,综合知识', 2017);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '通过浏览器访问网站管理系统，输入 www.xxx.com/login?f_page=-->" "><svg onload=prompt(/x/)>，结果如图 3-3 所示。 从图 3-3 可以看出，该网站存在（ ）漏洞，靖针对该漏洞提出相应防范措施。 备选答案： 答案解析： （1）主机 （2）物理 （3）应用 （4）网络', '["A. Java反序列化", "B. 跨站脚本攻击", "C. 远程命令执行", "D. SQL注入"]', '', '', 2, '2017年综合知识', '2017,综合知识', 2017);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '17.255/22主机位非全0和全1，是一个主机地址。 第25题：地址202.118.37.192/26是(24)，地址192.117.17.255/22是(25)。', '["A. 网络地址", "B. 组播地址", "C. 主机地址", "D. 定向广播地址"]', '', '', 2, '2018年综合知识', '2018,综合知识', 2018);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '17.255/22主机位非全0和全1，是一个主机地址。 第26题：将地址块192.168.0.0/24按照可变长 子网掩码 的思想进行子网划分，若各部门可用 主机地址 需求 如下表所示，则共有(26)种划分方案，部门3的掩码长度为(27)。 参考答案：C 解析 ：', '["A. 4", "B. 8", "C. 16", "D. 32"]', '', '', 2, '2018年综合知识', '2018,综合知识', 2018);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0.0/24先划分2个子网，1个子网给部门1，这里有2种情况，第二个子网再划 分2个子网，1个子网给部门2，这里又是2种情况，剩下的子网再划分2个子网，一个分 给部门3，还是2种情况，最后剩下的子网再分2个子网，一个给部门4、一个给部门5， 也是2种情况。 所以总的划分方案就是2*2*2*2=16种。其中部门3的主机只有16台，所以只需要5位主 机位，掩码长度32-5-27即可。 第27题：将地址块192.168.0.0/24按照可变长子网掩码的思想进行子网划分，若各部门可用 主机地址需求如下表所示，则共有(26)种划分方案，部门3的掩码长度为(27)。 参考答案：C', '["A. 25", "B. 26", "C. 27", "D. 28"]', '', '', 2, '2018年综合知识', '2018,综合知识', 2018);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0.0/24先划分2个子网，1个子网给部门1，这里有2种情况，第二个子网再划 分2个子网，1个子网给部门2，这里又是2种情况，剩下的子网再划分2个子网，一个分 给部门3，还是2种情况，最后剩下的子网再分2个子网，一个给部门4、一个给部门5， 也是2种情况。 所以总的划分方案就是2*2*2*2=16种。其中部门3的主机只有16台，所以只需要5位主 机位，掩码长度32-5-27即可。 第28题：若一个 组播组 包含6个成员， 组播服务器 所在 网络 有2个 路由器 ，当 组播服务器 发送 信息时需要发出()个分组。 参考答案：A 解析 ： 组播就是一组特定的对象，不管该组特定对象包含有多少个成员，针对一个组播服务只 需要发送一个组播包，组内成员都会收到。 第29题：在BGP4 协议 中，当出现 故障 时采用() 报文 发送给邻居。 参考答案：D 解析 ： BGP的四种报文：open，keepalive，update，notification。 其中OPEN是TCP连接建立后发送的第一个消息，用来建立BGP对等体之间的连接关系 并进行参数协商。 BGP会通过相互发送Keepalive的数据来维持邻居关系，默认每60秒发送一次，保持时', '["A. 1", "B. 2", "C. 3", "D. 6"]', '', '', 2, '2018年综合知识', '2018,综合知识', 2018);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '进程 P 有 8 个页面，页号分别为 0-7，页面大小为 4K，假设系统给进程 P 分配了 4 个存 储块 P， 进程P 的页面变换表如下所示。 表中状态位等于1 和 0 分别表示页面在内存和不在 内存。 若进程P 要访问的逻辑地址为十六进制 5148H， 则该地址经过变换后， 其物理地址应 为十六进制 （ ） ； 如果进程P 要访问的页面 6 不在内存， 那么应该淘汰页号为 （ ） 的页面。 页号 页帧号 状态位 访问位 修改位 0 -- 0 0 0 3 -- 0 0 0 4 -- 0 0 0 6 -- 0 0 0', '["A.3148H", "B.5148H", "C.7148H", "D.9148H"]', '', '', 2, '2019年综合知识', '2019,综合知识', 2019);
