INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '软件性能测试有多种不同类型测试方法， 其中， （ ） 用于测试在系统资源特别少的情况 下考查软件系统运行情况； （ ）用于测试系统可处理的同时在线的最大用户数量。', '["A.强度测试", "B.负载测试", "C.压力测试", "D.容量测试"]', '', '', 2, '2019年综合知识', '2019,综合知识', 2019);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '著作权中， （ ）的保护期不受期限。', '["A.发表权", "B.发行权", "C.展览权", "D.署名权"]', '', '', 2, '2019年综合知识', '2019,综合知识', 2019);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '在 HFC 网络中，Internet 接入采用的复用技术是（ ） ，其中下行信道不包括（ ）。 2019 年下半年网络规划设计师上午真题及答案解析 解析： 5148H 转换为十进制 20808，20808 除以 4096（4K）商 5 余 328，商 5 表示 5148H 对应的页 号为 5 号页，页内位置为 328。根据页表对应关系 5 号页对应 3 号物理块（页帧号） ，所以 此逻辑地址对应的物理地址：3*4096+328=12616，转十六进制为：3148H. 页面淘汰算法按照程序的局部性原理， 优先淘汰最近没有访问过的。 如果都访问过， 优先淘 汰没有修改过的。所以优先淘汰 2 号页。 二、小任老师网络工程师视频教程 小任老师网络工程师视频教程', '["A.FDM", "B.TDM", "C.CDM", "D.STDM"]', '', '', 2, '2019年综合知识', '2019,综合知识', 2019);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0kHz；ADSL 利用回声抵消，可实现上行和下行同时传输，且速率非对称，上行与下 行信道频率可部分重叠。 summer孇X Q èDe 18、以太网交换机中采用生成树算法是为了解决(18)问题。 18、【答案】C 【解析】送分题，必须拿分。 19、6个速率为 64Kb/s的用户按照统计时分多路复用技术(STDM)复用到一条干线上、 若每个用户平均效率为 80%，干线开销4%，则干线速率为(19) Kb/s。 19、【答案】C 【解析】网规2020 年考过的原题，干线速率计算：（64*6*80%）/（1-4%）=320Kbps 20、Internet网络核心采取的交换方式为(20)。 20、【答案】A 【解析】三种交换方式：电路交换、报文交换和分组交换，目前 Internet 应用最广的 是 IP 协议，属于分组交换。其他两种交换的特点和优缺点需要掌握。 21、以下关于虚电路交换技术的叙述中，错误的是(21)。 21、【答案】D 【解析】掌握几种交换方式。 22、SDH的帧结构包含(22)。 22、【答案】A 【解析】 summer孇X Q èDe 23、假设客户端采用持久型 HTTP 1.1 版本向服务器请求一个包含10个图片的网页。 设基页面传输时间为 Tbas，图片传输的平均时间为 Timg,客户端到服务器之间的往返 时间为 RTT，则从客户端请求开始到完整取回该网页所需时间为(23)。 23、【答案】D 【解析】根据选项倒推，10个图片，所有选项都是10Timg，即图片会请求10 次。基 础页面是1个框架，只需要请求1 次，即1xTbas，那么在A和D 中选择。根据前面推 断的10 次图片请求，1 次基础页面请求，然后包含返回的流量，即11 次往返，故 11xRTT，所以选D。 24、在CSMA/CD中，同一个冲突域中的主机连续经过3次冲突后，每个站点在接下来 信道空闲的时候立即传输的概率是(24)。 24、【答案】D 【解析】记住公式冲突概率1/2 n （n表示已经发生冲突的次数）。 25-26、在下图所示的网络拓扑中，假设自治系统AS3和AS2内部运行OSPF, AS1和 AS4内部运行 RIP。各自治系统间用BGP作为路由协议，并假设AS2和AS4 之间没有物 理链路。则路由器3c 基于(25)协议学习到网络x的可达性信息。1d通过(26)学习到x 的可达性信息。 summer孇X Q èDe 25-26、【答案】（25）C （26）B 【解析】考查基础路由学习，RIP的开销是跳数，选择跳数最小的路径。 27-28、Traceroute 在进行路由追踪时发出的 ICMP 消息(27)，收到的消息是中间节点 或目的节点返回的(28)。 27-28、【答案】（27）A （28）B 【解析】traceroute/tracert 每次发送TTL 递增的 echo Request 报文。 29、下列不属于快速 UDP 互联网连接(QUIC)协议的优势是(29)。 29、【答案】A 【解析】https://zhuanlan.zhihu.com/p/32553477 Quic相比现在广泛应用的 http2+tcp+tls 协议有如下优势[2]:', '["A.帧的转发", "B.短路", "C.环路", "D.生成转发表"]', '', '', 2, '2021年综合知识', '2021,综合知识', 2021);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '前向冗余纠错。 快速 UDP 互联网连接(QUIC)协议是基于 UDP进行改造，同时具备 UDP和TCP 部分功能 的协议。虽然 UDP不提供可靠的传输，但 QUIC 在基于 UDP 之上增加了一层带来可靠性 的层。它提供了数据包重传、拥塞控制、调整传输节奏(pacing) 以及其他一些TCP 中 存在的特性。TCP 都不能纠错，很明显基于 UDP的 QUIC也不能纠错。 summer孇X Q èDe 连接迁移 TCP 连接基于四元组(源 IP、源端口、目的 IP、目的端口)，切换网络时至少会有一个 因素发生变化，导致连接发生变化。当连接发生变化时，如果还使用原来的 TCP连 接，则会导致连接失败，就得等原来的连接超时后重新建立连接，所以我们有时候发 现切换到一个新网络时，即使新网络状况良好，但内容还是需要加载很久。如果实现 得好，当检测到网络变化时立刻建立新的 TCP连接，即使这样，建立新的连接还是需 要几百毫秒的时间。 QUIC 的连接不受四元组的影响，当这四个元素发生变化时，原连接依然维持。那这是 怎么做到的呢?道理很简单，QUIC 连接不以四元组作为标识，而是使用一一个 64 位的 随机数，这个随机数被称为 Connection ID，即使IP 或者端口发生变化，只要 Connection ID 没有变化，那么连接依然可以维持。 30、对于链路状态路由算法而言，若共有 N个路由器，路由器之间共有 M条链路，则 链路状态通告的消息复杂度以及接下来算法执行的时间复杂度分别是(30)。 )和 0(N ) )和 0(M ) 30、【答案】B 【解析】 31、距离向量路由协议所采用的核心算法是(31)。 31、【答案】D 【解析】距离矢量路由算法，基于 Bellman-Ford 算法。 32、IPv4 报文分片和重组分别发生在(32)。 32、【答案】B 【解析】分片发生在中间路由器，重组是在目的端。 summer孇X Q èDe 、下图为某网络拓扑的片段,将1 和 2两条链路聚合成链路 G1,并与链路3 形成 VRRP 主备关系，管理员发现在链路2 出现 CRC错误告警，此时该网络区域可能会发生的现 象是(33)。 户上网将会出现延迟卡顿 33、【答案】B 【解析】CRC 冗余告警可能是链路层有故障，导致数据丢包，从而通过链路2 的用户 会受到影响，经过链路1 的用户则无影响。 34-35、若循环冗余校验码 CRC 的生成器为 10111，则对于数据 10100010000 计算的校 验码应为(34)。该CRC 校验码能够检测出的突发错误不超过(35)。 （ 34-35、【答案】（34）A （35）B 【解析】掌握 CRC 计算过程，可以检测出小于等于校验位长度的突发错误。 36、(36)子系统是楼宇布线的组成部分。 36、【答案】C 【解析】掌握综合布线的几大子系统。 37、客户端通过 DHCP获得 IP地址的顺序正确的是(37)。 ①客户端发送DHCP REQUEST 请求 IP 地址 ②SERVER发送DHCP OFFER 报文响应 ③客户端发送DHCP DISCOVER 报文寻找DHCP SERVER ④SERVER 收到请求后回应 ACK响应请求 37、【答案】C summer孇X Q èDe 【解析】送分题，考查DHCP 过程。 38、某高校计划采用扁平化的网络结构。为了限制广播域、解决 VLAN资源紧缺的问 题，学校计划采用 QinQ(802.1Q-in-802.1Q)技术对接入层网络进行端口隔离。以下关 于 QinQ 技术的叙述中，错误的是(38)。 38、【答案】A 【解析】 • 基本 QinQ： 如果收到的是带有 VLAN Tag的报文，该报文就成为带双Tag的报 文。如果收到的是不带 VLAN Tag的报文，该报文就成为带有本端口缺省 VLAN Tag 的报文。 • 灵活 QinQ：为具有不同内层 VLAN ID的报文添加不同的外层 VLAN Tag。根据报文 内层 VLAN的802.1p 优先级标记外层 VLAN的802.1p 优先级和添加不同的外层 VLAN Tag。通过使用灵活 QinQ技术，在能够隔离运营商网络和用户网络的同时， 又能够提供丰富的业务特性和更加灵活的组网能力。 39、下面支持 IPv6的是 (39)。 39、【答案】C 【解析】支持 IPv6的路由协议：RIPng、OSPFv3、BGP4+。 40、以下关于OSPF 特性的叙述中，错误的是(40) 。 40、【答案】D 【解析】存在ABR的话，ABR是包含多个区域的LSDB，而普通的区域0的LSDB只含有 一部分LSA，就比如区域1的ABR 他的LSDB是含有区域1的LSA1和LSA2的，但是这 部分LSA是不会被传递到区域0的，所以不是所有的区域0的路由器的LSDB 都一样。 41、策略路由通常不支持根据(41)来指定数据包转发策略。 41、【答案】C 【解析】数据转发过程中，源MAC地址会发生变化。 42、SDN的网络架构中不包含(42)。 summer孇X Q èDe 42、【答案】A 【解析】SDN 实现控制层面与数据层面分离，上层是应用层。 43-44、窃取是一种针对数据或系统的(43)的攻击。DDoS 攻击可以破坏数据或系统的 (44)。 43-44、【答案】（43）B （44）A 【解析】网络安全基础。 45、以下关于 IPSec的说法中，错误的是(45) 。 45、【答案】B 【解析】IPSec 基础，必会。 46、是由我国自主研发的无线网络安全协议。 TKIP 46、【答案】A 【解析】记忆即可。 47-48、某 Web网站向 CA申请了数字证书。用户登录过程中可通过验证(47) 确认该证 书的有效性，以(48)。 47-48、【答案】（47）A （48）D 【解析】证书类似身份证，可以证实用户或网站的身份。 49、某公司要求数据备份周期为 7天，考虑到数据恢复的时间效率，需采用(49) 备 略。 49、【答案】A 【解析】完全备份恢复速度最快。 50、某网站的域名是 www.xyz.com，使用 SSL 安全页面，用户可以使用(50) 访问该网 站。 https://www.xyz.com summer孇X Q èDe 50、【答案】B 【解析】基础题，必须拿分。 51、以下关于链路加密的说法中，错误的是(51)。 51、【答案】B 【解析】链路加密如下图所示。 52-53 在运行OSPF的路由器中，可以使用(52) 命令查看OSPF进程下路由计算的统计 信息，使用(53) 命令查看OSPF 邻居状态信息。 52-53、【答案】（52）B （53）A 【解析】掌握 OSPF几个重要命令： display ospf cumulative 查看 OSPF统计信息 display ospf spf-statistics 查看 OSPF进程下路由计算的统计信息 display ospf interface 查看 OSPF的接口信息 display ospf peer 查看 OSPF的邻居信息 display ospf Isdb 查看 OSPF的 Isdb display ospf routing 查看 OSPF的路由信息 display ospf error 查看 OSPF错误信息 reset ospf process 重启 OSPF进程 54、以下关于 IPv6地址的说法中，错误的是(54) 。 54、【答案】B 【解析】::只能使用1 次。 summer孇X Q èDe 、在 IPv6 中，(55)首部是每个中间路由器都需要处理的。 55、【答案】A 【解析】顾名思义。 56、在 GPON中，上行链路采用(56)的方式传输数据。 DMA 56、【答案】A 【解析】PON 网络上行为 TDMA，下行为广播。 57、在 PON 中，上行传输波长为 (57)nm。 57、【答案】B 【解析】PON 上行波形为 1310nm，下行波长为 1490nm。 58、某居民小区采用 FTTB+HGW网络组网，通常情况下，网络中的(58)部署在汇聚机 房。 58、【答案】C 【解析】FTTB 是光纤到建筑，即 PON 网络，核心设备是 OLT 和ONU，其中 OLT 部署在 机房。 59、以下关于光功率计的功能的说法中，错误的是(59)。 59、【答案】D 【解析】OTDR才能在一端测得损耗。 60-61、8 块300G的硬盘做 RAID5 后的容量是(60)，RAID5 最多可以损坏(61) 块硬盘 而不丢失数据。 60-61、【答案】（60）B （61）B 【解析】RAID5 空间利用率是 N-1，最多可以损耗1 块硬盘，数据不丢失。 62、在无线网络中，通过射频资源管理可以配置的任务不包括(62)。 62、【答案】D summer孇X Q èDe 【解析】 • 射频优调：比如自动调整信道或发射功率。 • 智能漫游：在 WLAN 网络中会存在粘性终端，通过主动引导的方式，使终端漫游到 信号更强的 AP。 • 频谱导航：由于物理特性，双频设备的信号，2.4G的信号强于 5G，即使速率比 5G 的慢，所以大多数的移动设备优先连接 2.4G。双频设备打开频谱导航后，将其均 衡地连接至该设备的不同射频上。 • 终端定位需要根据多个 AP 信号差，或时间差进行计算。 63、在无线网络中，天线最基本的属性不包括(63)。 63、【答案】B 【解析】天线有 3 个最基本的属性：方向性、极化、增益。 64-65、下列路由表的概要信息中，迭代路由是(64)，不同的静态路由有(65)条。 <HUAWEI> display ip routing table Route Flags: R-relay, D-download to fib ----------------------------------------------------------------- Routing Tables: Public Destinations : 6 Routes: 7 Destination/Mask Proto Pre Cost Flags NextHop Interface.', '["A. O(M", "B. O(NM)和 0(N", "C. O(N", "D. O(NM)和 0(M"]', '', '', 2, '2021年综合知识', '2021,综合知识', 2021);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0.1/32 Direct 0 0 D 127.0.0.1 InLoopBack0 64-65、【答案】（64）B （65）C summer孇X Q èDe 【解析】Flag 带 R 的是迭代路由，迭代路由不论迭代出多少出接口和下一跳，仅统计 为一条路由。 （66）下列命令片段用于配置(66） <HUAWEI> system-view [~HUAWEI] interface 10ge1/0/1 [~HUAWEI-10GE1/0/1] loopback-detect enable [*HUAWEI-10GE1/0/1] commit 66、【答案】A 【解析】顾名思义，关键字 loopback-detect。 67、某主机可以 ping 通本机地址，而无法 ping通网关地址，网络配置如下图所示， 造成该故障的原因可能是(67) 。 67、【答案】B 【解析】缺图。 68-69、某分公司财务 PC 通过专网与总部财务系统连接，拓扑如下图所示。某天，财 务 PC 访问总部财务系统速度缓慢、时断时好，网络管理员在财务 PC 端ping总部财务 系统，发现有网络丢包，在光电转换器1 处 ping 总部财务系统网络丢包症状同上，在 专网接入终端处 ping 总部财务系统，网络延时正常无丢包，光纤1 两端测得光衰为- 28dBm，光电转换器1 和 2 指示灯绿色闪烁。初步判断该故障原因可能是(68)，可采用 (69)措施较为合理。 （69）A.更换财务 PC 终端网卡 68-69、【答案】（68）C （69）C summer孇X Q èDe 【解析】光纤光衰通常是指光纤每单位长度上的衰减值，单位为 dB/km。光衰理想的 范围：-20dBm 至 -25dBm。绿灯闪烁表示光电转换器没有问题。 70、以下关于项目风险管理的说法中，不正确的是(70) 。 70、【答案】A 【解析】风险无法完全避免。 71-75、Data security is the practice of protecting digital information from (71) access, corruption,or theft throughout its entire lifecycle. It is a concept that encompasses every aspect of information security from the (72) se curity of hardware and storage devices to administrative and access controls,as well as the logical security of software applications. It also in cludes organizational (73) and procedures.Data security involves deploying tools and technologies that enhance the organization''s Visibility into where its critical data resides and how itis used. These tools and te chnologies should (74) the growing challenges inherent in securing today''s complex distributed,hybrid,and/or multicloud computing environments.Ideally,these tools should be ableto apply protections like (75) ,data masking,and redaction of sensitive files, and should automate reporting to streamline audits and adhering to regulatory requirements. uthorized C .normal D. frequent ical C .network D. Information .policies D. structures .ignore D. pose ncryption C .decryption 71-75【答案】（71）A （72）B （73）C （74）A （75）B summer孇X Q èDe', '["A. 10.10.0.0/24", "B. 10.2.2.2/32", "C. 127.0.0.0/8", "D. 10.1.1.1/32"]', '', '', 2, '2021年综合知识', '2021,综合知识', 2021);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '并发性是指若干串件在（3)发生。', '["A. 同一时刻", "B. 同一时间间隔内", "C. 不同时间间隔内", "D. 不同时刻"]', '', '', 2, '2023年综合知识', '2023,综合知识', 2023);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '使用海明码进行纠错， 7位码片（x心X X,iX心X )， 其中4位数据位， 3位校验位， 其监督关系式为 。 C =XX X心 C1=X 沈XX7 C产沈XsXX 如果收到的码字为1000101， 则纠错后的码字是(4)。 X心X心X凶，那么 。 C= X 1 X 3 XsX 1 = 1+ 1+ 0+1= 1 c 1 = X心X 6 X 7 = 0+1+ 0+1= O C产X 4 X心X 7 = 0+0+0+1= 1 此处按偶校验， 则CCC。 =101，那么转换成10进制数就是5，证明第5位出错，所以原码字就为1010101。', '["A. 1000001", "B. 1001101", "C. 1010101", "D. 1000101"]', '', '', 2, '2023年综合知识', '2023,综合知识', 2023);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '奈奎斯特采样定理指出， 为了保证数字化过程不丢失信息， 采样频率必须高千信号带宽的(5)。', '["A. 2倍", "B. 1倍", "C. 4倍", "D. 8倍"]', '', '', 2, '2023年综合知识', '2023,综合知识', 2023);
