INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '给定一个长度为n的整数数组AI[1..n]，计算数组的最大连续子数组和。以下描述正确的是 (5) 。 ，这使得算法的时间复杂度为O (n2) 要从左到右遍历数组一次即可得出最优解，无需额外的存储空间来保存中间结 | 单选题', '["A. 在构建状态转移方程时，每个状态dp需要通过人遍历之前的所有元素来计", "B. 在构建状态转移方程时，可以只考虑当前元素AI]和前一个状态dp[i-1]", "D. 如果数组中所有的元素都为负数，那么算法将无法正确计算出最大子数组和"]', '', '', 2, '2024年综合知识', '2024,综合知识', 2024);
