INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '已知以太网最大帧长为1518B，IP和TCP最小报头和为40B，则可以传输的TCP数据最大 (23) B。 直播讲解过的原题，1518-18 (以太开销) -40 (IP+TCP报头) =1460B。 最新多机构网课联系微信: qingsongguo888 特价促销 | 单选题', '["A. 1460B", "B. 1480", "C. 1478", "D. 1500"]', '', '', 2, '2024年综合知识', '2024,综合知识', 2024);
