INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '下列关于网络性能技术指标的说法中错误的是 (16) 。 C 信道利用率是指一段时间内信道为占用状态的时间与总时间的比值，当信道利用率增大时，该信道引起的时延也会随之增加 网络时延肯定还包括发送时延。 | 单选题', '["A. 安全性目标是网络安全性问题不应干扰开展业务的能力", "B. 网络时延是从网络一端发送一个比特到网络的另一端接收到这个比特所经历的时间，即传播时延等于网络时延", "D. 响应时间是指从服务请求发出到接收到响应所花费的时间"]', '', '', 2, '2024年综合知识', '2024,综合知识', 2024);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'OOOO @错误，建立光纤骨干网络联通每个村镇的问题其实是最小生成树问题，而不是最短路径问题。最小生成树算法 (如 Kruskal 或 Prim) 用于连接所有节点 (村镇) 而不形成回路，并且总成本最 小。最短路径问题是从源到单个目标节点的路径选择。 | 单选题', '["C. @@O@O", "D. @®"]', '', '', 2, '2024年综合知识', '2024,综合知识', 2024);
